package inequivalent;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

class ClonePair923Method2Test {

    private final ClonePair923 subject = new ClonePair923();

    @Test
    void method2KeepsOnlyAllowedCharacterRanges() {
        // Generated by Codex (gpt-5.4).
        byte[] data = {47, 48, 65, 30, 31, 32, 122, 123};

        assertEquals("0A\u001E z", subject.method2(data, data.length));
    }

    @Test
    void method2UsesOnlyRequestedPrefixOfArray() {
        // Generated by Codex (gpt-5.4).
        byte[] data = {48, 65, 122, 123};

        assertEquals("0A", subject.method2(data, 2));
    }

    @Test
    void method2ReturnsEmptyStringForZeroLengthPrefix() {
        // Generated by Codex (gpt-5.4).
        assertEquals("", subject.method2(new byte[]{48, 65}, 0));
    }

    @Test
    void method2ThrowsArrayIndexOutOfBoundsExceptionWhenLengthExceedsArrayLength() {
        // Generated by Codex (gpt-5.4).
        assertThrows(ArrayIndexOutOfBoundsException.class, () -> subject.method2(new byte[]{48}, 2));
    }
}
